import{_ as i,c as l,o as a,a1 as t}from"./chunks/framework.DDNAyvCW.js";const p=JSON.parse('{"title":"Skills Troubleshooting & Best Practices","description":"","frontmatter":{},"headers":[],"relativePath":"docs/skills/troubleshooting/index.md","filePath":"docs/skills/troubleshooting/index.md"}'),o={name:"docs/skills/troubleshooting/index.md"};function r(s,e,n,c,d,u){return a(),l("div",null,e[0]||(e[0]=[t('<h1 id="skills-troubleshooting-best-practices" tabindex="-1">Skills Troubleshooting &amp; Best Practices <a class="header-anchor" href="#skills-troubleshooting-best-practices" aria-label="Permalink to &quot;Skills Troubleshooting &amp; Best Practices&quot;">​</a></h1><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><h3 id="writing-high‐quality-skills" tabindex="-1">Writing high‑quality Skills <a class="header-anchor" href="#writing-high‐quality-skills" aria-label="Permalink to &quot;Writing high‑quality Skills&quot;">​</a></h3><h4 id="_1-clear-naming-and-descriptions" tabindex="-1">1. Clear naming and descriptions <a class="header-anchor" href="#_1-clear-naming-and-descriptions" aria-label="Permalink to &quot;1. Clear naming and descriptions&quot;">​</a></h4><ul><li><p><strong>Write specific descriptions</strong></p><ul><li>Clearly explain the purpose and scenarios for the Skill.</li><li>Include important keywords to help the AI recognize when to use it.</li><li>State prerequisites and expected outcomes.</li></ul></li><li><p><strong>Use consistent naming</strong></p><ul><li>Choose clear, descriptive names.</li><li>Optionally add category prefixes such as <code>k8s-</code>, <code>docker-</code>, <code>git-</code>.</li><li>Keep naming conventions consistent across all Skills.</li></ul></li></ul><h4 id="_2-structured-steps" tabindex="-1">2. Structured steps <a class="header-anchor" href="#_2-structured-steps" aria-label="Permalink to &quot;2. Structured steps&quot;">​</a></h4><ul><li><p><strong>Keep the logic clear</strong></p><ul><li>Order steps by execution sequence.</li><li>Use numbered lists to make order explicit.</li><li>Add necessary decisions and branches where behavior splits.</li></ul></li><li><p><strong>Be detailed and concrete</strong></p><ul><li>Include full commands and parameters.</li><li>Explain the intent of each step.</li><li>Provide examples and expected outputs where helpful.</li></ul></li></ul><h4 id="_3-error-handling-and-rollback" tabindex="-1">3. Error handling and rollback <a class="header-anchor" href="#_3-error-handling-and-rollback" aria-label="Permalink to &quot;3. Error handling and rollback&quot;">​</a></h4><ul><li><p><strong>Handle failure cases</strong></p><ul><li>Identify likely error conditions.</li><li>Include steps for handling each error path.</li><li>Describe how to tell whether an operation succeeded or failed.</li></ul></li><li><p><strong>Define rollback procedures</strong></p><ul><li>For operations that might have impact, provide rollback steps.</li><li>Explain how to restore the system to its previous state.</li></ul></li></ul><h4 id="_4-maintainability" tabindex="-1">4. Maintainability <a class="header-anchor" href="#_4-maintainability" aria-label="Permalink to &quot;4. Maintainability&quot;">​</a></h4><ul><li><p><strong>Use variables instead of hard‑coding</strong></p><ul><li>Avoid hard‑coded values where possible.</li><li>Use placeholders to keep the Skill reusable.</li><li>Document what each variable means and its valid range.</li></ul></li><li><p><strong>Design with modularity</strong></p><ul><li>Break complex workflows into smaller, focused sections.</li><li>Make each step responsible for a single concern.</li><li>Keep Skills easy to test and modify over time.</li></ul></li></ul><h3 id="performance-optimization" tabindex="-1">Performance Optimization <a class="header-anchor" href="#performance-optimization" aria-label="Permalink to &quot;Performance Optimization&quot;">​</a></h3><h4 id="_1-control-the-number-of-enabled-skills" tabindex="-1">1. Control the number of enabled Skills <a class="header-anchor" href="#_1-control-the-number-of-enabled-skills" aria-label="Permalink to &quot;1. Control the number of enabled Skills&quot;">​</a></h4><ul><li><p><strong>Enable only what you need</strong></p><ul><li>Turn on only the Skills that you actively use.</li><li>Avoid enabling too many Skills at once.</li><li>Periodically clean up Skills that are no longer used.</li></ul></li><li><p><strong>Load by scenario</strong></p><ul><li>Switch different Skill sets based on the current task.</li><li>Use grouping to manage Skills by scenario.</li><li>Maintain different Skill collections for different workflows.</li></ul></li></ul><h4 id="_2-optimize-skill-content" tabindex="-1">2. Optimize Skill content <a class="header-anchor" href="#_2-optimize-skill-content" aria-label="Permalink to &quot;2. Optimize Skill content&quot;">​</a></h4><ul><li><p><strong>Streamline steps</strong></p><ul><li>Remove unnecessary steps.</li><li>Combine steps that can safely run in parallel.</li><li>Optimize the order of commands for faster feedback.</li></ul></li><li><p><strong>Reduce complexity</strong></p><ul><li>Avoid overly complex conditional logic inside a single Skill.</li><li>Split very complex Skills into multiple simpler Skills.</li><li>Store large blocks of content in resource files instead of inline text.</li></ul></li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><h3 id="terminal-skills-official-repository" tabindex="-1">Terminal Skills official repository <a class="header-anchor" href="#terminal-skills-official-repository" aria-label="Permalink to &quot;Terminal Skills official repository&quot;">​</a></h3><ul><li><strong>GitHub</strong>: <a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">chaterm/terminal-skills</a></li><li><strong>Description</strong>: A curated collection of terminal‑focused Skills covering a variety of operations and development use cases.</li></ul>',19)]))}const m=i(o,[["render",r]]);export{p as __pageData,m as default};
